import { httpClient } from './httpClient';
import {
  Salon,
  CreateSalonDto,
  UpdateSalonDto,
  SalonListParams,
  PaginatedSalons,
  SalonSettings,
  OpeningHours,
  OnlineBookingHours,
} from '@/types/salon';
import { API_CONFIG } from '@/config/api';

class SalonService {
  private readonly basePath = '/salons';

  async list(params?: SalonListParams): Promise<PaginatedSalons> {
    const queryParams = new URLSearchParams();

    if (params?.page) queryParams.append('page', params.page.toString());
    if (params?.limit) queryParams.append('limit', params.limit.toString());
    if (params?.sortBy) queryParams.append('sortBy', params.sortBy);
    if (params?.sortOrder) queryParams.append('sortOrder', params.sortOrder);
    if (params?.search) queryParams.append('search', params.search);
    if (params?.status) {
      queryParams.append('active', params.status === 'active' ? 'true' : 'false');
    }

    const response = await httpClient.get<PaginatedSalons | Salon[]>(
      `${this.basePath}${queryParams.toString() ? `?${queryParams.toString()}` : ''}`
    );

    // Check if response is an array (backend returning array directly)
    if (Array.isArray(response.data)) {
      // Convert array to paginated format
      const page = params?.page || 1;
      const limit = params?.limit || 10;
      return {
        data: response.data,
        total: response.data.length,
        page,
        limit,
        totalPages: Math.ceil(response.data.length / limit)
      };
    }

    return response.data;
  }

  async getById(id: string): Promise<Salon> {
    const response = await httpClient.get<Salon>(`${this.basePath}/${id}`);
    return response.data;
  }

  async getBySlug(slug: string): Promise<Salon> {
    const response = await httpClient.get<Salon>(`${this.basePath}/slug/${slug}`);
    return response.data;
  }

  async create(data: CreateSalonDto): Promise<Salon> {
    const response = await httpClient.post<Salon>(this.basePath, data);
    return response.data;
  }

  async createWithNetwork(data: CreateSalonDto): Promise<{ salon: Salon; network: any }> {
    const response = await httpClient.post<{ salon: Salon; network: any }>(
      `${this.basePath}/with-network`, 
      data
    );
    return response.data;
  }

  async update(id: string, data: UpdateSalonDto): Promise<Salon> {
    const response = await httpClient.put<Salon>(`${this.basePath}/${id}`, data);
    return response.data;
  }

  async delete(id: string): Promise<void> {
    await httpClient.delete(`${this.basePath}/${id}`);
  }

  async deleteSalon(id: string): Promise<void> {
    await httpClient.delete(`${this.basePath}/${id}`);
  }

  async activate(id: string): Promise<Salon> {
    const response = await httpClient.put<Salon>(`${this.basePath}/${id}/activate`);
    return response.data;
  }

  async deactivate(id: string): Promise<Salon> {
    const response = await httpClient.put<Salon>(`${this.basePath}/${id}/deactivate`);
    return response.data;
  }

  async uploadLogo(id: string, file: File): Promise<{ logoUrl: string }> {
    const formData = new FormData();
    formData.append('file', file);

    httpClient.setTimeoutForUploads();

    try {
      const response = await httpClient.post<{ logoUrl: string }>(
        `${this.basePath}/${id}/logo`,
        formData,
        {
          headers: {
            'Content-Type': 'multipart/form-data',
          },
        }
      );

      return response.data;
    } finally {
      httpClient.resetTimeout();
    }
  }

  async uploadImage(id: string, file: File): Promise<{ imageUrl: string }> {
    const formData = new FormData();
    formData.append('image', file);

    httpClient.setTimeoutForUploads();

    try {
      const response = await httpClient.post<{ imageUrl: string }>(
        `${this.basePath}/${id}/images`,
        formData,
        {
          headers: {
            'Content-Type': 'multipart/form-data',
          },
        }
      );

      return response.data;
    } finally {
      httpClient.resetTimeout();
    }
  }

  async deleteImage(id: string, imageUrl: string): Promise<void> {
    await httpClient.delete(`${this.basePath}/${id}/images`, {
      data: { imageUrl }
    });
  }

  async getDefaultSettings(): Promise<SalonSettings> {
    return {
      allowOnlineBooking: true,
      requireConfirmation: false,
      cancellationMinHours: 24,
      maxAdvanceBookingDays: 30,
      minAdvanceBookingHours: 2,
      blockScheduleAfterBooking: true,
      defaultServiceDuration: 60,
      slotInterval: 15
    };
  }

  async getDefaultOpeningHours(): Promise<OpeningHours[]> {
    const days = ['Segunda', 'Terça', 'Quarta', 'Quinta', 'Sexta', 'Sábado', 'Domingo'];

    return days.map((_, index) => ({
      dayOfWeek: index === 6 ? 0 : index + 1,
      open: index === 6 ? '09:00' : '08:00',
      close: index === 6 ? '13:00' : index === 5 ? '17:00' : '18:00',
      isOpen: index !== 6
    }));
  }

  async getWorkingHours(id: string): Promise<OpeningHours[]> {
    const salon = await this.getById(id);
    return salon.openingHours || await this.getDefaultOpeningHours();
  }

  async updateWorkingHours(id: string, workingHours: OpeningHours[]): Promise<Salon> {
    const response = await httpClient.put<Salon>(
      `${this.basePath}/${id}/working-hours`,
      workingHours
    );
    return response.data;
  }

  async getBookingSettings(id: string): Promise<SalonSettings> {
    const salon = await this.getById(id);
    return salon.settings || await this.getDefaultSettings();
  }

  async updateBookingSettings(id: string, settings: Partial<SalonSettings>): Promise<Salon> {
    const response = await httpClient.put<Salon>(
      `${this.basePath}/${id}/settings`,
      settings
    );

    return response.data;
  }

  validateCNPJ(cnpj: string): boolean {
    cnpj = cnpj.replace(/[^\d]+/g, '');

    if (cnpj.length !== 14) return false;

    if (/^(\d)\1{13}$/.test(cnpj)) return false;

    let tamanho = cnpj.length - 2;
    let numeros = cnpj.substring(0, tamanho);
    const digitos = cnpj.substring(tamanho);
    let soma = 0;
    let pos = tamanho - 7;

    for (let i = tamanho; i >= 1; i--) {
      soma += parseInt(numeros.charAt(tamanho - i)) * pos--;
      if (pos < 2) pos = 9;
    }

    let resultado = soma % 11 < 2 ? 0 : 11 - soma % 11;
    if (resultado !== parseInt(digitos.charAt(0))) return false;

    tamanho = tamanho + 1;
    numeros = cnpj.substring(0, tamanho);
    soma = 0;
    pos = tamanho - 7;

    for (let i = tamanho; i >= 1; i--) {
      soma += parseInt(numeros.charAt(tamanho - i)) * pos--;
      if (pos < 2) pos = 9;
    }

    resultado = soma % 11 < 2 ? 0 : 11 - soma % 11;
    if (resultado !== parseInt(digitos.charAt(1))) return false;

    return true;
  }

  formatCNPJ(cnpj: string): string {
    cnpj = cnpj.replace(/[^\d]+/g, '');
    return cnpj.replace(/^(\d{2})(\d{3})(\d{3})(\d{4})(\d{2})$/, '$1.$2.$3/$4-$5');
  }

  formatPhone(phone: string): string {
    phone = phone.replace(/[^\d]+/g, '');
    if (phone.length === 11) {
      return phone.replace(/^(\d{2})(\d{5})(\d{4})$/, '($1) $2-$3');
    } else if (phone.length === 10) {
      return phone.replace(/^(\d{2})(\d{4})(\d{4})$/, '($1) $2-$3');
    }
    return phone;
  }

  generateSlug(name: string): string {
    return name
      .toLowerCase()
      .normalize('NFD')
      .replace(/[\u0300-\u036f]/g, '')
      .replace(/[^a-z0-9]+/g, '-')
      .replace(/^-+|-+$/g, '');
  }

  // Online Booking Hours Methods

  async getOnlineBookingHours(id: string): Promise<OnlineBookingHours[]> {
    const response = await httpClient.get<OnlineBookingHours[]>(
      `${this.basePath}/${id}/online-booking-hours`
    );
    return response.data;
  }

  async updateOnlineBookingHours(
    id: string,
    hours: OnlineBookingHours[]
  ): Promise<OnlineBookingHours[]> {
    const response = await httpClient.put<OnlineBookingHours[]>(
      `${this.basePath}/${id}/online-booking-hours`,
      hours
    );
    return response.data;
  }
}

export const salonService = new SalonService();
