          street: "",
          number: "",
          complement: "",
          neighborhood: "",
          city: "",
          state: "",
          zipCode: "",
        },
        tags: client.tags || [],
        preferredProfessionalId: client.preferredProfessionalId || "",
      });
    } else {
      // Limpar formulário em modo criação
      setFormData({
        fullName: "",
        cpf: "",
        birthDate: undefined,
        gender: "",
        phone: "",
        email: "",
        instagram: "",
        observations: "",
        address: {
          street: "",
          number: "",
          complement: "",
