        }
      }
    };

    fetchHistory();
  }, [activeTab, client?.id, clientHistory]);

  // Debounced CPF check
  const checkCpfAvailability = useCallback(
    debounce(async (cpf: string) => {
      if (!cpf || cpf.length < 14) return;

      const cleanedCpf = cleanCPF(cpf);
      if (!validateCPF(cleanedCpf)) return;

      // Don't check if editing and CPF hasn't changed
      if (isEditing && client?.cpf === cleanedCpf) return;

      try {
