                </div>

                {/* Grid Responsivo - CPF e Nascimento */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4"> {/* RESP: Grid 1 col no mobile, 2 no desktop */}
                  {/* CPF */}
                  <div className="flex flex-col gap-[4px]">
                    <Label htmlFor="cpf">CPF</Label>
                    <div className="relative">
                      <Input
                        id="cpf"
                        value={formData.cpf}
                        onChange={(e) => handleCpfChange(e.target.value)}
                        placeholder="000.000.000-00"
                        maxLength={14}
                        className={cn("salon-input w-full", errors.cpf && "border-destructive")}
                      />
                      {checkingCpf && (
                        <LoadingSpinner size="sm" inline className="absolute right-3 top-1/2 -translate-y-1/2" />
                      )}
                    </div>
                    {errors.cpf && (
                      <p className="text-destructive text-xs mt-1">{errors.cpf}</p>
                    )}
                  </div>

                  {/* Data de Nascimento */}
                  <div className="flex flex-col gap-[4px]">
                    <Label>Data de Nascimento</Label>
                    <DatePickerWithSelects
                      date={formData.birthDate}
                      onSelect={(date) => handleFieldChange("birthDate", date)}
                      placeholder="Selecione a data"
                      disabled={(date) =>
                        date > new Date() || date < new Date("1900-01-01")
                      }
                      // Note: DatePickerWithSelects internal classes should ideally handle w-full
                    />
                  </div>
                </div>

                {/* Grid Responsivo - Gênero e Telefone */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {/* Gênero */}
                  <div className="flex flex-col gap-[4px]">
                    <Label>Gênero</Label>
                    <Select
                      value={formData.gender}
                      onValueChange={(value) =>
                        handleFieldChange("gender", value)
                      }
                    >
                      <SelectTrigger className="salon-input w-full">
                        <SelectValue placeholder="Selecione o gênero" />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="feminino">Feminino</SelectItem>
                        <SelectItem value="masculino">Masculino</SelectItem>
                        <SelectItem value="outro">Outro</SelectItem>
                        <SelectItem value="nao_informar">
                          Prefiro não informar
                        </SelectItem>
                      </SelectContent>
                    </Select>
                  </div>

                  {/* Telefone */}
                  <div className="flex flex-col gap-[4px]">
                    <Label htmlFor="phone">
                      Celular com DDD <span className="text-destructive">*</span>
                    </Label>
                    <Input
                      id="phone"
                      value={formData.phone}
                      onChange={(e) =>
                        handleFieldChange("phone", formatPhone(e.target.value))
                      }
                      placeholder="(00) 00000-0000"
                      maxLength={15}
                      className={cn("salon-input w-full", errors.phone && "border-destructive")}
                    />
                    {errors.phone && (
                      <p className="text-destructive text-xs mt-1">{errors.phone}</p>
                    )}
                  </div>
                </div>

                {/* Grid Responsivo - E-mail e Instagram */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {/* E-mail */}
                  <div className="flex flex-col gap-[4px]">
                    <Input
                      id="email"
                      label="E-mail"
                      type="email"
                      value={formData.email}
                      onChange={(e) => handleFieldChange("email", e.target.value)}
                      placeholder="cliente@email.com"
                      className={cn("salon-input w-full", errors.email && "border-destructive")}
                    />
                    {errors.email && (
                      <p className="text-destructive text-xs">{errors.email}</p>
                    )}
                  </div>

                  {/* Instagram */}
                  <Input
                    id="instagram"
                    label="Instagram"
                    value={formData.instagram}
                    onChange={(e) =>
                      handleFieldChange("instagram", e.target.value)
                    }
                    placeholder="@usuario"
                    className="salon-input w-full"
                  />
                </div>

                {/* Observações - Sempre Full Width */}
                <div className="flex flex-col gap-[4px]">
                  <Label htmlFor="observations">
                    Observações internas
                  </Label>
                  <Textarea
                    id="observations"
                    value={formData.observations}
                    onChange={(e) =>
                      handleFieldChange(
                        "observations",
                        e.target.value.slice(0, 200)
                      )
                    }
                    placeholder="Digite observações relevantes sobre o cliente..."
                    maxLength={200}
                    rows={4}
                    className="salon-input min-h-[100px] resize-none w-full"
                  />
                </div>
              </TabsContent>

              {isEditing && (
                <TabsContent value="history" className="mt-0 space-y-6">
                  {loadingHistory ? (
                    <div className="flex justify-center items-center h-64">
                      <LoadingSpinner size="md" />
                    </div>
                  ) : clientHistory ? (
                    <div className="space-y-6">
                      <div className="grid grid-cols-2 md:grid-cols-4 gap-3 md:gap-4">
                        <div className="bg-tertiary/30 p-4 rounded-lg border border-tertiary">
                          <p className="text-[10px] uppercase font-bold text-muted-foreground mb-1">Visitas</p>
                          <p className="text-[18px] font-black text-primary">
                            {clientHistory.statistics?.totalVisits || 0}
                          </p>
                        </div>
                        <div className="bg-tertiary/30 p-4 rounded-lg border border-tertiary">
                          <p className="text-[10px] uppercase font-bold text-muted-foreground mb-1">Gasto</p>
                          <p className="text-[18px] font-black text-primary">
                            R$ {(clientHistory.statistics?.totalSpent || 0).toFixed(0)}
                          </p>
                        </div>
                        <div className="bg-tertiary/30 p-4 rounded-lg border border-tertiary">
                          <p className="text-[10px] uppercase font-bold text-muted-foreground mb-1">Ticket</p>
                          <p className="text-[18px] font-black text-primary">
                            R$ {(clientHistory.statistics?.averageTicket || 0).toFixed(0)}
                          </p>
                        </div>
                        <div className="bg-tertiary/30 p-4 rounded-lg border border-tertiary">
                          <p className="text-[10px] uppercase font-bold text-muted-foreground mb-1">Última</p>
                          <p className="text-[18px] font-black text-primary leading-tight mt-1">
                            {clientHistory.statistics?.lastVisit
                              ? format(
                                  new Date(clientHistory.statistics.lastVisit),
                                  "dd/MM/yy",
                                  { locale: ptBR }
                                )
                              : "Nunca"}
                          </p>
                        </div>
                      </div>

                      <div className="space-y-4">
                        <h3 className="text-base font-semibold">Histórico recente</h3>
                        {clientHistory.appointments &&
                        clientHistory.appointments.length > 0 ? (
                          <div className="space-y-3">
                            {clientHistory.appointments.map((appointment) => (
                              <div
                                key={appointment.id}
                                className="salon-card p-4 border-border/60"
                              >
                                <div className="flex justify-between items-start gap-4">
                                  <div className="space-y-1">
                                    <p className="font-bold text-foreground">
                                      {appointment.date
                                        ? format(
                                            new Date(appointment.date),
                                            "dd/MM/yyyy 'às' HH:mm",
                                            { locale: ptBR }
                                          )
                                        : "N/A"}
                                    </p>
                                    <p className="text-xs text-muted-foreground">
                                      Profissional: <span className="text-foreground font-medium">{appointment.professional?.name || "N/A"}</span>
                                    </p>
                                    <div className="text-xs text-muted-foreground pt-1 flex flex-wrap gap-1">
                                      {appointment.services?.map((s, idx) => (
                                        <span key={idx} className="bg-secondary/50 px-2 py-0.5 rounded text-primary font-medium">
                                          {s?.name}
                                        </span>
                                      )) || "Nenhum serviço"}
                                    </div>
                                  </div>
                                  <div className="text-right shrink-0">
                                    <p className="font-black text-primary">
                                      R$ {(appointment.totalAmount || 0).toFixed(2)}
                                    </p>
                                    <span className={cn(
                                      "text-[10px] font-bold uppercase px-2 py-0.5 rounded-full ml-auto",
                                      appointment.status === 'concluido' ? "bg-green-100 text-green-700" : "bg-muted text-muted-foreground"
                                    )}>
                                      {appointment.status || "Pendente"}
                                    </span>
                                  </div>
                                </div>
                              </div>
                            ))}
                          </div>
                        ) : (
                          <div className="text-center py-8 text-[13px] text-muted-foreground bg-tertiary/30 rounded-lg border border-tertiary">
                            Nenhum atendimento registrado
                          </div>
                        )}
                      </div>
                    </div>
                  ) : (
                    <div className="text-center py-12">Erro ao carregar histórico</div>
                  )}
                </TabsContent>
              )}
            </DialogBody>
          </Tabs>

          <DialogFooter className="border-t pt-6 shrink-0">
            {isEditing && onDelete ? (
              <div className="flex flex-col sm:flex-row justify-between w-full gap-3">
                <Button
                  variant="outline"
                  disabled={!selectedSalon?.active}
                  onClick={() => setShowDeleteConfirm(true)}
                  className="text-destructive border-destructive hover:bg-destructive/10 hover:text-destructive w-full sm:w-auto"
                >
                  <Trash2 className="h-4 w-4 mr-2" />
                  Excluir Cliente
                </Button>

                <div className="flex flex-col-reverse sm:flex-row gap-2 sm:gap-3 sm:ml-auto">
                  <Button variant="outline" onClick={onClose} className="w-full sm:w-auto">
                    Cancelar
                  </Button>
                  <Button
                    disabled={!selectedSalon?.active}
                    onClick={handleSave}
                    className="w-full sm:w-auto"
                  >
                    {saveButtonText}
                  </Button>
                </div>
              </div>
            ) : (
              <>
                <Button variant="outline" onClick={onClose} className="w-full sm:w-auto">
                  Cancelar
                </Button>
                <Button
                  disabled={!selectedSalon?.active}
                  onClick={handleSave}
                  className="w-full sm:w-auto"
                >
                  {saveButtonText}
                </Button>
              </>
            )}
          </DialogFooter>
        </DialogContent>
      </Dialog>


      {/* Modal de Confirmação de Exclusão */}
      <ConfirmationModal
        isOpen={showDeleteConfirm}
        onClose={() => setShowDeleteConfirm(false)}
        onConfirm={handleDelete}
        title="Excluir Cliente"
        description="Você tem certeza que deseja excluir este cliente? Esta ação não pode ser desfeita."
        confirmText="Excluir"
        variant="destructive"
      />
    </>
  );
}
